by_file.into_iter().map(|(file_path, entities)| {
        let best = entities.iter()
            .max_by(|a, b| a.score.partial_cmp(&b.score).unwrap_or(std::cmp::Ordering::Equal))
            .unwrap(); // safe: entities is non-empty

        RelevantFile {
            file_path,
            relevance_score: best.score,
            reason: best.reason.clone(),
            entities: entities.into_iter().map(|se| se.entity).collect(),
            stale_warning: None, // populated by QueryEngine after ranking
        }
    }).collect

sorted.iter().take(5).map(|(id, deg)| {
            if let Some(e) = graph.entities.get(**id) {
                format!("- **{}** (`{}`) -{} connections", e.name, e.file_path, deg)
            } else {
                format!("- `{}` -{} connections", id, deg)
            }
        }).collect

graph.edges.iter().filter_map(|(caller, callee)| {
            let cd = caller.split('/').nth(1).unwrap_or("");
            let td = callee.split('/').nth(1).unwrap_or("");
            if cd != td && !cd.is_empty() && !td.is_empty() {
                let cn = caller.split("::").last().unwrap_or(caller);
                let tn = callee.split("::").last().unwrap_or(callee);
                Some(format!("- `{cn}` → `{tn}` (cross-module)"))
            } else {
                None
            }
        }).take(5).collect

